import { boolean, integer, varchar, index, uniqueIndex } from 'drizzle-orm/pg-core';
import { sql } from 'drizzle-orm';

export const users = pgTable(
  'users',
  {
    id: uuid('id').primaryKey().default(sql`gen_random_uuid()`),
    email: varchar('email', { length: 255 }).notNull().unique(),
    name: varchar('name', { length: 255 }).notNull(),
    password_hash: varchar('password_hash', { length: 255 }),
    role: varchar('role', { length: 32 }).notNull().default('user'),
    email_verified: boolean('email_verified').notNull().default(false),
    email_verified_at: timestamp('email_verified_at', { withTimezone: true }),
    failed_login_count: integer('failed_login_count').notNull().default(0),
    locked_until: timestamp('locked_until', { withTimezone: true }),
    mfa_enabled: boolean('mfa_enabled').notNull().default(false),
    mfa_secret_enc: text('mfa_secret_enc'),
    mfa_recovery_codes_enc: text('mfa_recovery_codes_enc'),
    mfa_verified_at: timestamp('mfa_verified_at', { withTimezone: true }),
    mfa_failed_count: integer('mfa_failed_count').notNull().default(0),
    mfa_locked_until: timestamp('mfa_locked_until', { withTimezone: true }),
    last_login: timestamp('last_login', { withTimezone: true }),
    deleted_at: timestamp('deleted_at', { withTimezone: true }),
    created_at: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
    updated_at: timestamp('updated_at', { withTimezone: true }).notNull().defaultNow(),
  },
  (table) => ({
    emailIdx: index('users_email_idx').on(table.email),
  }),
);

export const refreshTokens = pgTable(
  'refresh_tokens',
  {
    id: uuid('id').primaryKey().default(sql`gen_random_uuid()`),
    user_id: uuid('user_id')
      .notNull()
      .references(() => users.id, { onDelete: 'cascade' }),
    session_id: uuid('session_id').notNull(),
    token_hash: varchar('token_hash', { length: 64 }).notNull().unique(),
    ip_address: varchar('ip_address', { length: 64 }),
    user_agent: text('user_agent'),
    expires_at: timestamp('expires_at', { withTimezone: true }).notNull(),
    revoked_at: timestamp('revoked_at', { withTimezone: true }),
    rotated_to: uuid('rotated_to'),
    replay_detected_at: timestamp('replay_detected_at', { withTimezone: true }),
    created_at: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
  },
  (table) => ({
    userIdIdx: index('refresh_tokens_user_id_idx').on(table.user_id),
    sessionIdIdx: index('refresh_tokens_session_id_idx').on(table.session_id),
  }),
);

export const verificationTokens = pgTable(
  'verification_tokens',
  {
    id: uuid('id').primaryKey().default(sql`gen_random_uuid()`),
    user_id: uuid('user_id')
      .notNull()
      .references(() => users.id, { onDelete: 'cascade' }),
    kind: varchar('kind', { length: 32 }).notNull(),
    token_hash: varchar('token_hash', { length: 64 }).notNull(),
    expires_at: timestamp('expires_at', { withTimezone: true }).notNull(),
    consumed_at: timestamp('consumed_at', { withTimezone: true }),
    created_at: timestamp('created_at', { withTimezone: true }).notNull().defaultNow(),
  },
  (table) => ({
    tokenHashUq: uniqueIndex('verification_tokens_token_hash_uq').on(table.token_hash),
    userIdKindIdx: index('verification_tokens_user_id_kind_idx').on(table.user_id, table.kind),
  }),
);
